const BATCH_SIZE = 12;
for (let i = 0; i < files.length; i += BATCH_SIZE) {
    const batch = files.slice(i, i + BATCH_SIZE);
    iframe.srcdoc = `<div style="color:#666; font-family:sans-serif; text-align:center; padding:20px;">Fetching Module: ${i}/${files.length}...</div>`;
    await Promise.all(batch.map(async (file) => {
        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'preview_file', file_path: file.path, ref_sha: sha })
            });
            const data = await res.json();
            if (data.content) {
                const ext = file.path.split('.').pop().toLowerCase();
                fileCache[file.path] = { 
                    content: (['png', 'jpg', 'jpeg', 'gif', 'svg', 'ico'].includes(ext)) ? data.content : b64DecodeUnicode(data.content),
                    ext, sha: file.sha 
                };
            }
        } catch(e) { console.error("Fetch fail", file.path); }
    }));
}

