async function fetchSqlSchema() {
    const container = document.getElementById('sqlPillContainer');
    const status = document.getElementById('sqlStatusText');
    try {
        const sql = "SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' AND table_type = 'BASE TABLE' ORDER BY table_name;";
        const res = await callSqlEdgeFunction(sql);
        container.innerHTML = '';
        res.data.forEach(row => {
            const btn = document.createElement('button');
            btn.className = 'table-pill px-4 py-1.5 rounded-full bg-white/5 border border-white/10 text-xs font-medium text-slate-400 active:scale-95';
            btn.innerText = row.table_name;
            btn.onclick = () => {
                document.querySelectorAll('.table-pill').forEach(p => p.classList.remove('active'));
                btn.classList.add('active');
                document.getElementById('sqlEditor').value = 'SELECT * FROM public."' + row.table_name + '" LIMIT 20;';
            };
            container.appendChild(btn);
        });
        status.innerText = "Schema Updated";
    } catch (err) {
        status.innerText = "Schema Sync Error";
    }
}

async function runSqlQuery() {
    const sql = document.getElementById('sqlEditor').value;
    const loader = document.getElementById('sqlLoader');
    const output = document.getElementById('sqlResultOutput');
    const statusText = document.getElementById('sqlStatusText');
    const statusDot = document.getElementById('sqlStatusDot');
    const copyBtn = document.getElementById('sqlCopyBtn');
    if (!sql.trim()) return;
    loader.classList.remove('hidden');
    copyBtn.classList.add('hidden');
    statusDot.className = "w-1.5 h-1.5 rounded-full bg-yellow-500 animate-pulse";
    statusText.innerText = "Running...";
    try {
        const result = await callSqlEdgeFunction(sql);
        lastSqlResultData = result.data;
        renderSqlResultTable(result.data);
        statusText.innerText = 'Success: ' + (result.count || result.data.length) + ' rows';
        statusDot.className = "w-1.5 h-1.5 rounded-full bg-green-500";
        copyBtn.classList.remove('hidden');
    } catch (err) {
        output.innerHTML = '<div class="p-6 bg-red-500/5 text-red-400 m-4 rounded-xl border border-red-500/20 font-mono text-xs"><p class="font-bold mb-1 uppercase">[Error]</p>' + err.message + '</div>';
        statusText.innerText = "Query Failed";
        statusDot.className = "w-1.5 h-1.5 rounded-full bg-red-500";
    } finally {
        loader.classList.add('hidden');
    }
}

function renderSqlResultTable(data) {
    const output = document.getElementById('sqlResultOutput');
    if (!data || data.length === 0) {
        output.innerHTML = '<div class="p-20 text-center text-slate-500 text-xs uppercase tracking-widest">Empty Result Set</div>';
        return;
    }
    const cols = Object.keys(data[0]);
    let html = '<div class="overflow-auto h-full"><table class="w-full text-left border-collapse">';
    html += '<thead class="sticky top-0 z-10 bg-[#0a0a0a]"><tr>';
    cols.forEach(c => {
        html += '<th class="p-3 border-b border-white/10 text-[9px] font-black uppercase text-blue-500 tracking-tighter">' + c + '</th>';
    });
    html += '</tr></thead><tbody class="divide-y divide-white/5">';
    data.forEach((row, idx) => {
        html += '<tr class="' + (idx % 2 === 0 ? 'bg-transparent' : 'bg-white/[0.01]') + '">';
        cols.forEach(c => {
            const val = row[c];
            let display = val;
            if (val === null) display = '<span class="opacity-20">NULL</span>';
            else if (typeof val === 'object') display = '<span class="text-blue-400/80 underline">JSON</span>';
            else if (typeof val === 'boolean') display = val ? 'TRUE' : 'FALSE';
            html += '<td class="p-3 truncate text-slate-400 border-r border-white/5 result-cell">' + display + '</td>';
        });
        html += '</tr>';
    });
    html += '</tbody></table></div>';
    output.innerHTML = html;
}

async function pasteToSqlEditor() {
    try {
        const text = await navigator.clipboard.readText();
        if (text) document.getElementById('sqlEditor').value = text;
    } catch(e) { showGlobalToast('Clipboard access denied', true); }
}

function clearSqlEditor() { document.getElementById('sqlEditor').value = ''; }

function copySqlResults() {
    if (!lastSqlResultData) return;
