// --- KEY TESTER LOGIC ---
function openKeyTester() {
    const overlay = document.getElementById('key-tester-overlay');
    overlay.style.display = 'flex';
    setTimeout(() => overlay.classList.add('active'), 10);
    toggleFab(false);

    const savedKey = localStorage.getItem('conduit_tester_gemini_key');
    if (savedKey) document.getElementById('tester-apiKey').value = savedKey;
}

function closeKeyTester() {
    const overlay = document.getElementById('key-tester-overlay');
    overlay.classList.remove('active');
    setTimeout(() => overlay.style.display = 'none', 300);
    toggleFab(true);
}

async function fetchTesterModels() {
    const key = document.getElementById('tester-apiKey').value;
    const modelSelect = document.getElementById('tester-modelList');
    if (!key) return alert("Enter API Key first.");

    try {
        const res = await fetch('https://generativelanguage.googleapis.com/v1beta/models?key=' + key);
        const data = await res.json();
        if (data.error) throw new Error(data.error.message);

        modelSelect.innerHTML = '';
        data.models.forEach(m => {
            if (m.supportedGenerationMethods.includes("generateContent")) {
                const opt = document.createElement('option');
                opt.value = m.name;
                opt.textContent = m.displayName;
                modelSelect.appendChild(opt);
            }
        });
        showGlobalToast("Models loaded successfully");
    } catch (e) { alert("Error: " + e.message); }
}

async function sendTesterMessage() {
    const key = document.getElementById('tester-apiKey').value;
    const modelSelect = document.getElementById('tester-modelList');
    const model = modelSelect.value;
    const input = document.getElementById('tester-userInput');
    const container = document.getElementById('tester-chat-container');
    const text = input.value.trim();

    if (!key || !model || !text) return alert("Key, Model, and Message are all required.");

    appendTesterMsg(text, 'tester-user');
    input.value = '';
    const botMsgDiv = appendTesterMsg("...", 'tester-bot');

    try {
        const res = await fetch('https://generativelanguage.googleapis.com/v1beta/' + model + ':generateContent?key=' + key, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ contents: [{ parts: [{ text: text }] }] })
        });

        const data = await res.json();
        if (data.error) throw new Error(data.error.message);
        const responseText = data.candidates[0].content.parts[0].text;
        botMsgDiv.innerText = responseText;
    } catch (e) { botMsgDiv.innerText = "Error: " + e.message; }
    container.scrollTop = container.scrollHeight;
}

function appendTesterMsg(text, sender) {
    const div = document.createElement('div');
    div.className = 'tester-msg ' + sender;
    div.innerText = text;
    document.getElementById('tester-chat-container').appendChild(div);
    return div;
}

