                    <div class="status-badge px-2 py-1 rounded text-[10px] font-black uppercase tracking-tighter bg-slate-700 text-slate-400">PENDING</div>
                </div>
                <div class="result-area"><p class="text-[10px] text-slate-600 mt-2">Pinging Gemini 2.5 Flash...</p></div>`;
            container.appendChild(row);

            const success = await validateTesterKey(keyData.api_key, row);
            if (success) {
                validCount++;
                validLabel.innerText = validCount;
            }
        });
    } catch (err) {
        container.innerHTML = '<div class="p-4 bg-red-900/20 text-red-200 rounded-xl">Error: ' + err.message + '</div>';
    }
}

async function validateTesterKey(apiKey, element) {
    const resultArea = element.querySelector('.result-area');
    const badge = element.querySelector('.status-badge');
    try {
        const res = await fetch('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ contents: [{ parts: [{ text: "Hello, respond with exactly one word: 'OK'." }] }] })
        });
        const data = await res.json();
        if (res.ok) {
            badge.innerText = "SUCCESS";
            badge.className = "status-badge px-2 py-1 rounded text-[10px] font-black uppercase tracking-tighter bg-teal-900/40 text-teal-400";
            resultArea.innerHTML = `<p style="color:#10b981; font-size:12px; margin-top:4px;">✓ Response: ${data.candidates[0].content.parts[0].text.trim()}</p>`;
            return true;
        } else {
            badge.innerText = data.error?.status || "ERROR";
            badge.className = "status-badge px-2 py-1 rounded text-[10px] font-black uppercase tracking-tighter bg-red-900/40 text-red-400";
            resultArea.innerHTML = `<p style="color:#ef4444; font-size:11px; margin-top:4px; font-family:monospace;">✕ ${data.error?.message || 'API Error'}</p>`;
            return false;
        }
    } catch (err) {
        badge.innerText = "FAILED";
        resultArea.innerHTML = '<p style="color:#ef4444; font-size:11px; margin-top:4px;">✕ Network Error</p>';
        return false;
    }
}

